class Solution {
public:
    int vowelStrings(vector<string>& words, int left, int right) {
        int count = 0;
        string vowels = "aeiou";
        for (int i = left; i <= right; i++) {
            if (vowels.find(words[i][0]) != string::npos && vowels.find(words[i].back()) != string::npos) {
                count++;
            }
        }
        return count;
    }
};
